import requests

def fetch_url_content(url: str) -> str:
    try:
        response = requests.get(url, timeout=10)
        response.raise_for_status()
        return response.text
    except requests.exceptions.Timeout:
        return f"Error: Request to {url} timed out after 10 seconds."
    except requests.exceptions.HTTPError as e:
        status_code = e.response.status_code
        response_text_snippet = e.response.text[:200] if e.response.text else "No response body."
        return f"Error: HTTP error occurred for {url} - Status Code: {status_code}. Details: {response_text_snippet}..."
    except requests.exceptions.ConnectionError:
        return f"Error: Could not connect to {url}. Check URL or network."
    except requests.exceptions.RequestException as e:
        return f"Error: An unexpected request error occurred for {url} - {e}"
    except Exception as e:
        return f"Error: An unexpected error occurred - {e}"